const range = document.querySelectorAll('A1:D1');
range.forEach(cell => {
  cell.style.backgroundColor = 'lightblue';
  cell.style.fontWeight = 'bold';
});

from openpyxl.styles import PatternFill, Font
ws = workbook.active
for row in ws['A1:D1']:
    for cell in row:
        cell.fill = PatternFill(fgColor='ADD8E6')
        cell.font = Font(bold=True)

XSSFSheet sheet = workbook.getSheetAt(0);
for (int i = 0; i <= 3; i++) {
    Cell cell = sheet.getRow(0).getCell(i);
    cell.getCellStyle().setFillForegroundColor(new XSSFColor());
}

SELECT cell_range, background_color, font_weight
FROM excel_formatting
WHERE cell_range = 'A1:D1';
